#include<bits/stdc++.h>
using namespace std;
long long n,k,X,Y;
long long x[1000010],y[100010],s[1000010],l[1000010],r[1000010];
void calc(long long xx,long long yy)
{
    long long pos=xx*X+yy*Y;
    for(long long i=1;i<=n;i++)
    {
        s[i]=s[i-1]+xx*x[i]+yy*y[i]+k;
    }
    if(s[n]==0)
    {
        for(long long i=1;i<=n;i++)
        {
            if(s[i]<pos)
            {
                r[i]=-1;
            }
        }
        return;
    }
    for(long long i=1;i<=n;i++)
    {
        if(s[n]>0)
        {
            if(s[i]<pos)
            {
                l[i]=max(l[i],(pos-s[i])/s[n]+((pos-s[i])%s[n]!=0?1:0));
            }
        }
        else
        {
            if(s[i]<pos)
            {
                r[i]=-1;
            }
            else
            {
                r[i]=min(r[i],(pos-s[i])/s[n]);
            }
        }
    }
}
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        scanf("%lld%lld%lld%lld",&n,&k,&X,&Y);
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld%lld",&x[i],&y[i]);
            l[i]=0;
            r[i]=1e15;
        }
        if(X==0&&Y==0)
        {
            printf("0\n");
            continue;
        }
        calc(1,1);
        calc(1,-1);
        calc(-1,1);
        calc(-1,-1);
        long long ans=LLONG_MAX;
        for(long long i=1;i<=n;i++)
        {
            if(l[i]<=r[i])
            {
                ans=min(ans,l[i]*n+i);
            }
        }
        if(ans>1e18)
        {
            printf("-1\n");
        }
        else
        {
            printf("%lld\n",ans);
        }
    }
    return 0;
}
